const customers = [
  { id: 'DEMO_STRESSED_001', name: 'Rahul Verma', city: 'Delhi', region: 'North', salary: 40000 },
  { id: 'DEMO_STRESSED_002', name: 'Priya Sharma', city: 'Mumbai', region: 'West', salary: 55000 },
  { id: 'DEMO_HEALTHY_001', name: 'Arjun Nair', city: 'Bangalore', region: 'South', salary: 120000 },
  { id: 'DEMO_HEALTHY_002', name: 'Meera Iyer', city: 'Chennai', region: 'South', salary: 65000 },
  { id: 'DEMO_CRITICAL_001', name: 'Vikram Singh', city: 'Jaipur', region: 'North', salary: 22000 }
];

const categories = ['lending_app', 'gambling', 'lottery', 'grocery', 'dining', 'payday_lender', 'cash_advance', 'utility'];
const customer = customers[Math.floor(Math.random() * customers.length)];
const category = categories[Math.floor(Math.random() * categories.length)];
const amount = Math.floor(Math.random() * 20000) + 500;
const isStress = ['lending_app','gambling','lottery','payday_lender','cash_advance'].includes(category);

return [{
  json: {
    customer_id: customer.id,
    customer_name: customer.name,
    city: customer.city,
    region: customer.region,
    salary: customer.salary,
    txn_type: 'upi',
    merchant_category: category,
    amount: amount,
    is_stress_category: isStress,
    direction: 'debit',
    channel: 'mobile',
    status: Math.random() > 0.1 ? 'success' : 'failed',
    timestamp: new Date().toISOString()
  }
}];

const txn = $('Generate Transaction').first().json;
const score = $('Score Customer').first().json;

const riskTier = score.risk_score >= 0.7 ? '🔴 CRITICAL' : '🟡 WATCH';
const topDriver = score.shap_drivers && score.shap_drivers.length > 0 
  ? score.shap_drivers[0].feature 
  : 'unknown';

const message = `${riskTier} | ${txn.customer_name} (${txn.city})\n` +
  `Risk Score: ${(score.risk_score * 100).toFixed(1)}%\n` +
  `Top Driver: ${topDriver}\n` +
  `Last Txn: ${txn.merchant_category} ₹${txn.amount.toLocaleString()}\n` +
  `Recommended: ${score.risk_score >= 0.7 ? 'Escalation Call' : 'Wellness Check-in'}`;

return [{ json: { 
  alert_message: message,
  customer_id: txn.customer_id,
  customer_name: txn.customer_name,
  risk_score: score.risk_score,
  risk_tier: score.risk_score >= 0.7 ? 'critical' : 'watch',
  top_driver: topDriver,
  city: txn.city,
  last_category: txn.merchant_category,
  last_amount: txn.amount
}}];

const txn = $('Generate Transaction').first().json;
const score = $('Score Customer').first().json;

return [{ json: {
  status: '✅ STABLE',
  customer_name: txn.customer_name,
  risk_score: score.risk_score || 0,
  last_txn: `${txn.merchant_category} ₹${txn.amount}`
}}];
